            <!-- Progress Bar -->
            <div style="background: #1e293b; border-radius: 8px; height: 12px; overflow: hidden; margin-bottom: 16px;">
              <div style="background: ${r}; height: 100%; width: ${Math.min(e.percentage,100)}%; border-radius: 8px;"></div>
            </div>

