    `}}function EY(e,t,n){const r=Math.max(...e.monthlyBreakdown.map(o=>Math.max(o.income,o.expense)),1),a=e.monthlyBreakdown.map(o=>{const s=Math.max(Math.round(o.income/r*100),2),c=Math.max(Math.round(o.expense/r*100),2);return`
      <tr>
